import { clsx } from 'clsx';
const tones:Record<string,string>={active:'bg-emerald-100 text-emerald-700 dark:bg-emerald-950 dark:text-emerald-300',inactive:'bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-300',on_hold:'bg-amber-100 text-amber-700 dark:bg-amber-950 dark:text-amber-300',expiring:'bg-amber-100 text-amber-700 dark:bg-amber-950 dark:text-amber-300',archived:'bg-red-100 text-red-700 dark:bg-red-950 dark:text-red-300',draft:'bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-300',expired:'bg-red-100 text-red-700 dark:bg-red-950 dark:text-red-300',terminated:'bg-red-100 text-red-700 dark:bg-red-950 dark:text-red-300',renewed:'bg-blue-100 text-blue-700 dark:bg-blue-950 dark:text-blue-300',received:'bg-blue-100 text-blue-700 dark:bg-blue-950 dark:text-blue-300',under_review:'bg-amber-100 text-amber-700 dark:bg-amber-950 dark:text-amber-300',accepted:'bg-emerald-100 text-emerald-700 dark:bg-emerald-950 dark:text-emerald-300',rejected:'bg-red-100 text-red-700 dark:bg-red-950 dark:text-red-300'};
